     4→import { applyGravity } from "./gravity.js";
     5→import { findMatches } from "./match-detector.js";
     6→import { processMerges, calculateMiddlePositions } from "./merge-processor.js";
     7→import { getDisplayValue } from "./tile-helpers.js";
