// Monte Carlo Tree Search hint system
// Evaluates moves with multi-step lookahead via random rollouts

import { simulateMove } from "./simulation.js";
import { findAllValidSwaps } from "./hint-system.js";

const MCTS_DEFAULT_CONFIG = {
    iterations: 500,
    rolloutDepth: 4,
    explorationConstant: 1.41,
    maxChildren: 30,
    timeLimit: 2000,
};

class MCTSNode {
    constructor(board, swap = null, parent = null) {
        this.board = board;
        this.swap = swap;
        this.parent = parent;
        this.children = [];
        this.visits = 0;
        this.totalReward = 0;
        this.untriedSwaps = null; // lazy init
    }

    get avgReward() {
        return this.visits ? this.totalReward / this.visits : 0;
    }

    ucb1(parentVisits, C) {
        if (this.visits === 0) return Infinity;
        return this.avgReward + C * Math.sqrt(Math.log(parentVisits) / this.visits);
    }
}

/**
 * Deep-clone a board (2D array of tile objects).
 */
function cloneBoard(board) {
    return board.map((row) =>
        row.map((tile) => {
            if (!tile) return null;
            const c = { ...tile };
            if (tile.rectAnchor) c.rectAnchor = { ...tile.rectAnchor };
            if (tile.cellMergeCounts) c.cellMergeCounts = { ...tile.cellMergeCounts };
            return c;
        }),
    );
}

/**
 * Build a minimal game-like proxy with a given board, forwarding all
 * other required fields from the live game.  simulateMove() uses this
 * to create its own internal sim context.
 */
function makeProxy(game, board) {
    return Object.assign(Object.create(null), game, { board });
}

/**
 * Evaluate result of a simulateMove call into a reward number.
 */
function evaluateResult(result, game) {
    let reward = 0;
    reward += result.scoreDelta * 0.01;
    reward += result.cascades * 50;

    for (const [tileValue, count] of Object.entries(result.goalProgress)) {
        const goal = game.levelGoals.find(
            (g) => g.tileValue == tileValue && g.goalType === "created",
        );
        if (goal) {
            const remaining = goal.target - (goal.created || 0);
            const progress = Math.min(count, remaining);
            reward += progress * 200;
        }
    }

    return reward;
}

/**
 * Simulate random moves from a board state and return accumulated reward.
 */
function rollout(board, game, depth) {
    let currentBoard = cloneBoard(board);
    let totalReward = 0;

    for (let i = 0; i < depth; i++) {
        const proxy = makeProxy(game, currentBoard);
        const swaps = findAllValidSwaps(proxy);
        if (swaps.length === 0) break;

        const swap = swaps[Math.floor(Math.random() * swaps.length)];
        const result = simulateMove(proxy, swap);
        if (!result.valid) continue;

        totalReward += evaluateResult(result, game);
        currentBoard = result.newBoard;
    }

    return totalReward;
}

/**
 * Find the best swap using MCTS.
 * @param {Match3Game} game - The live game instance (not mutated)
 * @param {object} config - Optional MCTS configuration overrides
 * @returns {{row1, col1, row2, col2, score, visits, totalIterations} | null}
 */
export function findBestSwapMCTS(game, config = {}) {
    const {
        iterations = MCTS_DEFAULT_CONFIG.iterations,
        rolloutDepth = MCTS_DEFAULT_CONFIG.rolloutDepth,
        explorationConstant = MCTS_DEFAULT_CONFIG.explorationConstant,
        maxChildren = MCTS_DEFAULT_CONFIG.maxChildren,
        timeLimit = MCTS_DEFAULT_CONFIG.timeLimit,
    } = config;

    const root = new MCTSNode(cloneBoard(game.board));
    const startTime = Date.now();

    for (let i = 0; i < iterations; i++) {
        if (Date.now() - startTime > timeLimit) break;

        // 1. Selection: walk tree using UCB1 until we find a node with untried swaps
        let node = root;
        while (
            node.untriedSwaps !== null &&
            node.untriedSwaps.length === 0 &&
            node.children.length > 0
        ) {
            node = node.children.reduce((best, child) =>
                child.ucb1(node.visits, explorationConstant) >
                best.ucb1(node.visits, explorationConstant)
                    ? child
                    : best,
            );
        }

        // 2. Expansion: lazy-init untriedSwaps, then expand one
        if (node.untriedSwaps === null) {
            const proxy = makeProxy(game, node.board);
            let swaps = findAllValidSwaps(proxy);
            // Limit branching factor — shuffle then slice
            if (swaps.length > maxChildren) {
                for (let j = swaps.length - 1; j > 0; j--) {
                    const k = Math.floor(Math.random() * (j + 1));
                    [swaps[j], swaps[k]] = [swaps[k], swaps[j]];
                }
                swaps = swaps.slice(0, maxChildren);
            }
            node.untriedSwaps = swaps;
        }

        if (node.untriedSwaps.length > 0) {
            const swapIdx = Math.floor(Math.random() * node.untriedSwaps.length);
            const swap = node.untriedSwaps.splice(swapIdx, 1)[0];

            const proxy = makeProxy(game, node.board);
            const result = simulateMove(proxy, swap);

            if (result.valid) {
                const child = new MCTSNode(result.newBoard, swap, node);
                node.children.push(child);
                node = child;
            }
        }

        // 3. Rollout
        const rolloutReward = rollout(node.board, game, rolloutDepth);

        // 4. Backpropagation
        let cur = node;
        while (cur) {
            cur.visits++;
            cur.totalReward += rolloutReward;
            cur = cur.parent;
        }
    }

    if (root.children.length === 0) return null;

    // Pick child with most visits (robust selection)
    const bestChild = root.children.reduce((a, b) => (a.visits > b.visits ? a : b));

    return {
        row1: bestChild.swap.row1,
        col1: bestChild.swap.col1,
        row2: bestChild.swap.row2,
        col2: bestChild.swap.col2,
        score: bestChild.avgReward,
        visits: bestChild.visits,
        totalIterations: root.visits,
    };
}

