#!/usr/bin/env node
// Headless level simulator
// Usage: node scripts/simulate.js [options]
//
// Options:
//   --level <n>        Level index (1-based, default: 1)
//   --runs <n>         Number of plays (default: 20)
//   --strategy <name>  "mcts" | "hint" | "random" (default: mcts)
//   --mcts-iters <n>   MCTS iterations (default: 500)
//   --mcts-depth <n>   MCTS rollout depth (default: 4)
//   --mcts-time <ms>   MCTS time limit ms (default: 2000)
//   --config <key>     Level config set: "new" | "test" (default: new)
//   --verbose          Print per-run details
//   --help             Show this help

import { parseArgs } from "node:util";
import { findBestSwapMCTS } from "../src/mcts.js";
import { findBestSwap, findAllValidSwaps } from "../src/hint-system.js";
import { simulateMove } from "../src/simulation.js";
import { createBoard } from "../src/board.js";
import { findMatches, checkTFormation, checkLFormation, checkBlockFormation } from "../src/match-detector.js";
import { isBlocked, isBlockedWithLife, isBlockedWithMergeCount, isRectangularBlocked } from "../src/tile-helpers.js";
import { DEFAULT_LEVEL, LEVEL_CONFIGS, DEFAULT_TILE_VALUES } from "../src/config.js";

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

const { values: args } = parseArgs({
    options: {
        level:       { type: "string",  short: "l", default: "1" },
        runs:        { type: "string",  short: "r", default: "20" },
        strategy:    { type: "string",  short: "s", default: "mcts" },
        "mcts-iters":{ type: "string",  default: "500" },
        "mcts-depth":{ type: "string",  default: "4" },
        "mcts-time": { type: "string",  default: "2000" },
        config:      { type: "string",  short: "c", default: "new" },
        verbose:     { type: "boolean", short: "v", default: false },
        help:        { type: "boolean", short: "h", default: false },
    },
    strict: false,
});

if (args.help) {
    console.log(`Usage: node scripts/simulate.js [options]

Options:
  --level <n>        Level index (1-based, default: 1)
  --runs <n>         Number of plays (default: 20)
  --strategy <name>  mcts | hint | random (default: mcts)
  --mcts-iters <n>   MCTS iterations per move (default: 500)
  --mcts-depth <n>   MCTS rollout depth (default: 4)
  --mcts-time <ms>   MCTS time limit ms (default: 2000)
  --config <key>     Level config set: new | test (default: new)
  --verbose          Print per-run details
  --help             Show this help`);
    process.exit(0);
}

const levelIdx  = parseInt(args.level, 10) - 1;
const runs      = parseInt(args.runs, 10);
const strategy  = args.strategy;
const mctsIters = parseInt(args["mcts-iters"], 10);
const mctsDepth = parseInt(args["mcts-depth"], 10);
const mctsTime  = parseInt(args["mcts-time"], 10);
const configKey = args.config;
const verbose   = args.verbose;

// ---------------------------------------------------------------------------
// Level config resolution
// ---------------------------------------------------------------------------

const levelConfigSet = LEVEL_CONFIGS.find((c) => c.key === configKey);
if (!levelConfigSet) {
    console.error(`Unknown config key "${configKey}". Available: ${LEVEL_CONFIGS.map((c) => c.key).join(", ")}`);
    process.exit(1);
}

const levels = levelConfigSet.levels;
if (levelIdx < 0 || levelIdx >= levels.length) {
    console.error(`Level ${levelIdx + 1} not found. Config "${configKey}" has ${levels.length} level(s).`);
    process.exit(1);
}

const levelConfig = levels[levelIdx];

// ---------------------------------------------------------------------------
// Game context factory
// ---------------------------------------------------------------------------

/**
 * Build a minimal game-like object from a level config.
 * Mirrors what game.js does in loadLevel() — no DOM, no storage.
 */
function createGameContext(levelConfig) {
    const tileValues = levelConfig.spawnableTiles || DEFAULT_TILE_VALUES;

    const game = {
        board: [],
        boardWidth:  levelConfig.boardWidth  || 8,
        boardHeight: levelConfig.boardHeight || 8,
        tileValues,
        spawnableTileValues: tileValues,
        levelConfig,
        blockedTiles: levelConfig.blockedTiles || [],
        specialTileConfig: levelConfig.specialTileConfig || {
            line_4: "freeswap_horizontal",
            block_4: "freeswap_horizontal",
            line_5: "joker",
            t_formation: "freeswap",
            l_formation: "freeswap",
        },
        allowNonMatchingSwaps: levelConfig.allowNonMatchingSwaps || false,
        levelGoals: levelConfig.goals.map((g) => ({ ...g })),
        maxMoves: levelConfig.maxMoves,
        movesUsed: 0,
        score: 0,
        cursedTileCreatedCount: {},

        // Methods required by board.js during initial board generation
        checkTFormation(row, col, value) { return checkTFormation(this, row, col, value); },
        checkLFormation(row, col, value)  { return checkLFormation(this, row, col, value); },
        checkBlockFormation(row, col, value) { return checkBlockFormation(this, row, col, value); },
    };

    createBoard(game);
    return game;
}

// ---------------------------------------------------------------------------
// Board inspection helpers
// ---------------------------------------------------------------------------

/** Count blocked tiles on the board (all variants). */
function countBlockedTiles(board) {
    const seen = new Set(); // avoid double-counting shared rectangular tile objects
    let count = 0;
    for (const row of board) {
        for (const tile of row) {
            if (!tile) continue;
            if (isBlocked(tile) || isBlockedWithLife(tile) || isBlockedWithMergeCount(tile)) {
                const key = tile.rectId || `${tile.row}_${tile.col}_${Math.random()}`; // unique key
                if (isRectangularBlocked(tile)) {
                    if (!seen.has(tile.rectId)) {
                        seen.add(tile.rectId);
                        count++;
                    }
                } else {
                    count++;
                }
            }
        }
    }
    return count;
}

/** Count tiles of a specific value on the board. */
function countTileValue(board, tileValue) {
    let count = 0;
    for (const row of board) {
        for (const tile of row) {
            if (tile && tile.value === tileValue) count++;
        }
    }
    return count;
}

// ---------------------------------------------------------------------------
// Goal checking
// ---------------------------------------------------------------------------

/**
 * Check if all level goals are met given current state.
 * - "created": cumulative progress tracked in goalTotals
 * - "blocked":  initialBlockedCount - currentBlockedCount >= target
 * - "current":  live board tile count for tileValue >= target
 * - "score":    not simulated (treated as always met)
 */
function checkGoalsMet(levelConfig, goalTotals, board, initialBlockedCount) {
    for (const goal of levelConfig.goals) {
        if (goal.goalType === "created") {
            const achieved = goalTotals[goal.tileValue] || 0;
            if (achieved < goal.target) return false;
        } else if (goal.goalType === "blocked") {
            const currentBlocked = countBlockedTiles(board);
            const cleared = initialBlockedCount - currentBlocked;
            // target is set dynamically in the real game to initialBlockedCount
            const target = goal.target || initialBlockedCount;
            if (cleared < target) return false;
        } else if (goal.goalType === "current") {
            const onBoard = countTileValue(board, goal.tileValue);
            if (onBoard < goal.target) return false;
        }
        // "score" — not simulated, treated as always met
    }
    return true;
}

// ---------------------------------------------------------------------------
// Strategy: random swap (among swaps that produce a match)
// ---------------------------------------------------------------------------

function randomSwap(game) {
    const swaps = findAllValidSwaps(game);
    if (swaps.length === 0) return null;

    // Filter to swaps that actually produce a match (mirrors what simulateMove checks)
    const validSwaps = swaps.filter((s) => {
        const r = simulateMove(game, s);
        return r.valid && r.scoreDelta > 0;
    });

    if (validSwaps.length === 0) {
        // No matching swaps exist — fall back to any swap (allowNonMatchingSwaps boards)
        return swaps[Math.floor(Math.random() * swaps.length)];
    }
    return validSwaps[Math.floor(Math.random() * validSwaps.length)];
}

// ---------------------------------------------------------------------------
// Single run simulation
// ---------------------------------------------------------------------------

/**
 * Simulate one full level play.
 * @returns {{ won: boolean, movesUsed: number, goalTotals: object }}
 */
function simulateRun(levelConfig, strategyFn) {
    const game = createGameContext(levelConfig);
    const goalTotals = {}; // accumulated "created" goal progress
    const initialBlockedCount = countBlockedTiles(game.board);

    // Apply any pre-existing goal.created values (some levels start with progress)
    for (const goal of levelConfig.goals) {
        if (goal.goalType === "created" && goal.created) {
            goalTotals[goal.tileValue] = goal.created;
        }
    }

    while (game.movesUsed < game.maxMoves) {
        const swap = strategyFn(game);
        if (!swap) break; // no valid moves

        const result = simulateMove(game, swap);
        if (!result.valid) {
            if (game.allowNonMatchingSwaps) {
                // Non-matching swap allowed — counts as a move
                game.board = result.newBoard;
                game.movesUsed++;
            } else {
                // Strategy returned a swap that produces no match.
                // This shouldn't happen with a well-behaved strategy, but
                // rather than infinite loop, treat as no valid moves.
                break;
            }
            continue;
        }

        // Accumulate "created" goal progress
        for (const [tileValue, count] of Object.entries(result.goalProgress)) {
            goalTotals[tileValue] = (goalTotals[tileValue] || 0) + count;
        }

        // Update game state for next move
        game.board = result.newBoard;
        game.movesUsed++;

        if (checkGoalsMet(levelConfig, goalTotals, game.board, initialBlockedCount)) {
            return { won: true, movesUsed: game.movesUsed, goalTotals };
        }
    }

    return { won: false, movesUsed: game.movesUsed, goalTotals };
}

// ---------------------------------------------------------------------------
// Strategy picker
// ---------------------------------------------------------------------------

function buildStrategyFn(strategy, mctsConfig) {
    switch (strategy) {
        case "mcts":
            return (game) => findBestSwapMCTS(game, mctsConfig);
        case "hint":
            return (game) => findBestSwap(game);
        case "random":
            return (game) => randomSwap(game);
        default:
            console.error(`Unknown strategy "${strategy}". Use: mcts | hint | random`);
            process.exit(1);
    }
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

const mctsConfig = {
    iterations: mctsIters,
    rolloutDepth: mctsDepth,
    timeLimit: mctsTime,
};

const strategyFn = buildStrategyFn(strategy, mctsConfig);

console.log(`\nLevel ${levelIdx + 1}: "${levelConfig.title}"`);
console.log(`Config: ${configKey}  Strategy: ${strategy}  Runs: ${runs}`);
if (strategy === "mcts") {
    console.log(`MCTS: iters=${mctsIters}  depth=${mctsDepth}  timeLimit=${mctsTime}ms`);
}
console.log(`Goals: ${levelConfig.goals.map((g) => `${g.goalType}:${g.tileValue || ""}×${g.target}`).join(", ")}`);
console.log(`Moves: ${levelConfig.maxMoves}  Board: ${levelConfig.boardWidth || 8}×${levelConfig.boardHeight || 8}`);
console.log("─".repeat(50));

let wins = 0;
let totalMoves = 0;
const startTime = Date.now();

for (let i = 0; i < runs; i++) {
    const result = simulateRun(levelConfig, strategyFn);
    if (result.won) wins++;
    totalMoves += result.movesUsed;

    if (verbose) {
        const status = result.won ? "WIN " : "LOSS";
        const goals = Object.entries(result.goalTotals)
            .map(([v, c]) => `${v}:${c}`)
            .join(" ");
        console.log(`  Run ${String(i + 1).padStart(3)}: ${status}  moves=${result.movesUsed}  goals={${goals}}`);
    }
}

const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
const winRate = ((wins / runs) * 100).toFixed(1);
const avgMoves = (totalMoves / runs).toFixed(1);

console.log("─".repeat(50));
console.log(`Results: ${wins}/${runs} won  (${winRate}% win rate)`);
console.log(`Avg moves used: ${avgMoves} / ${levelConfig.maxMoves}`);
console.log(`Total time: ${elapsed}s`);

